#!/usr/bin/env python3
"""Decode quality report card + admission gate (ZERO runtime cost — post-hoc on a
bench-decode-next profile). Grades a profile AAA..F by sustained tok/s against
mesh-decode-budget.json, prints a where-the-time-goes breakdown, and (with
--min-grade) exits nonzero to REJECT a candidate that doesn't earn prod.

Usage:
  curl ... /__mesh/bench-decode-next?... -H 'X-Mesh-Profile-Token: $T' > prof.json
  python3 admit-decode-profile.py prof.json                 # report card
  python3 admit-decode-profile.py prof.json --min-grade AA  # admission gate (exit 1 if < AA)

Accepts: the raw curl response {code,stdout,...}, OR the decode-next-summary
object, OR any JSON containing a `summary` with *_mean_us + tps + divergent_tokens.
"""
import json
import re
import sys
from pathlib import Path

HERE = Path(__file__).resolve().parent
BUDGET = json.loads((HERE / "mesh-decode-budget.json").read_text())
GRADES = BUDGET["grades"]
# Order best->worst; F handled specially (0 tps or divergence).
ORDER = ["AAA", "AA", "A", "B", "C", "D", "F"]
BYTES = BUDGET["components_bytes_gb"]


def find_summary(obj):
    """Pull the decode-next-summary dict out of whatever was passed."""
    if isinstance(obj, dict):
        if "summary" in obj and isinstance(obj["summary"], dict) and "tps" in obj["summary"]:
            return obj["summary"]
        if "tps" in obj and "divergent_tokens" in obj:
            return obj
        # raw curl response: parse the summary JSON line out of stdout
        out = obj.get("stdout", "")
        for line in out.splitlines():
            line = line.strip()
            if line.startswith('{"kind":"decode-next-summary"'):
                return json.loads(line)["summary"]
    raise SystemExit("could not locate a decode-next-summary in the input JSON")


def grade_for(tps, divergent):
    if divergent and divergent > 0:
        return "F"
    if tps <= 0:
        return "F"
    if tps < 1.0:
        return "D"
    for g in ["AAA", "AA", "A", "B", "C"]:
        if tps >= GRADES[g]["min_tps"]:
            return g
    return "D"


def main():
    args = sys.argv[1:]
    min_grade = None
    if "--min-grade" in args:
        i = args.index("--min-grade")
        min_grade = args[i + 1]
        del args[i:i + 2]
    src = Path(args[0]).read_text() if args else sys.stdin.read()
    s = find_summary(json.loads(src, strict=False))

    tps = float(s.get("tps") or 0.0)
    divergent = int(s.get("divergent_tokens") or 0)
    fwd_ms = float(s.get("forward_mean_us") or 0.0) / 1000.0
    grade = grade_for(tps, divergent)

    def ms(k):
        return float(s.get(k + "_mean_us") or 0.0) / 1000.0

    comps = [
        ("qkv_matvec", "QKV proj"),
        ("o_matvec", "O proj"),
        ("ffn_matvec", "FFN gate+up+down"),
        ("logit_matvec", "logit (lm_head)"),
    ]
    print(f"\n=== DECODE QUALITY REPORT CARD — {BUDGET['model']} ===")
    print(f"  GRADE: {grade}  ({GRADES[grade]['label']})")
    print(f"  sustained: {tps:.2f} tok/s   forward: {fwd_ms:.1f} ms/token   divergent_tokens: {divergent}")
    if divergent:
        print("  !! CORRECTNESS FAILURE (divergent_tokens>0) -> automatic F regardless of speed")
    print("  component            measured   ~bytes(q8)   ~GB/s")
    for k, label in comps:
        t = ms(k)
        gb = (BYTES.get(k) or {}).get("q8")
        bw = (gb / (t / 1000.0)) if (gb and t > 0) else 0.0
        gbtxt = f"{gb:.2f} GB" if gb else "   -  "
        print(f"  {label:<19} {t:7.1f}ms   {gbtxt:>9}   {bw:6.0f}")
    print(f"  attention {ms('attention'):.1f}ms | non-matvec floor ~{BUDGET['non_matvec_floor_ms']['total']}ms")
    # next grade up: what's needed
    cur = ORDER.index(grade)
    if cur > 0:
        nxt = ORDER[cur - 1]
        need_tps = GRADES[nxt]["min_tps"]
        need_fwd = 1000.0 / need_tps if need_tps > 0 else 0
        print(f"  to reach {nxt}: >= {need_tps:.0f} tok/s  (forward <= {need_fwd:.1f} ms; shave {max(0,fwd_ms-need_fwd):.1f} ms)")

    if min_grade:
        ok = ORDER.index(grade) <= ORDER.index(min_grade)
        verdict = "ADMIT" if ok else "REJECT"
        print(f"\n  ADMISSION (min {min_grade}): {verdict}  (got {grade})")
        sys.exit(0 if ok else 1)
    print()


if __name__ == "__main__":
    main()
